mapper.select:
select Count(*)
from   furniture
where  f_code = #{f_code}

select * from ( select rownum rnum, data.* from ( select f_code, c_id, c_kind, c_name, f_name, f_price, f_dprice, f_createddate, f_catagory1, f_catagory2, f_catagory3, f_catagory4, f_catagory5, f_discount, f_point, f_count, f_viewcount, f_deliveryPrice, r_count, s_count from furniture left join (select f_code as furniturecode, count(*) as r_count from f_review group by f_code) rv on rv.furniturecode = furniture.f_code left join (select f_code as furniturecode, COALESCE(sum(f_count),0) as s_count from cart where CART.f_status = 'Y' group by f_code) sales on sales.furniturecode = furniture.f_code where ${searchKey} like '%' || #{searchValue} || '%'
and f_catagory1 = #{f_catagory1}
and f_catagory2 = #{f_catagory2}
and f_catagory3 = #{f_catagory3}
and f_catagory4 = #{f_catagory4}
and f_catagory5 = #{f_catagory5}
order by f_createddate asc
order by f_dprice desc
order by f_dprice asc
order by f_viewcount desc
order by f_viewcount asc
order by f_discount desc, f_createddate desc
order by NVL(r_count, 0) desc, f_createddate desc
order by NVL(s_count, 0) desc, f_createddate desc
order by f_createddate desc
) data )
where rnum >= #{start} and rnum <= #{end}

