WITH TARGET_FURNITURE AS (SELECT * FROM FURNITURE F
AND F.C_ID = #{c_id}
AND F.C_KIND = #{c_kind} AND F.C_NAME = #{c_name}
), REVIEW_SUMMARY AS (SELECT R.F_CODE, COUNT(CASE WHEN R.FR_IDX > 0 THEN 1 END) AS r_count, COUNT(CASE WHEN R.FR_IDX < 0 THEN 1 END) AS a_count, AVG(CASE WHEN R.FR_IDX > 0 THEN R.FR_STAR END) AS star_avg FROM F_REVIEW R JOIN TARGET_FURNITURE TF ON R.F_CODE = TF.F_CODE GROUP BY R.F_CODE), CART_SUMMARY AS (SELECT C.F_CODE, SUM(C.F_COUNT) AS cart_total_f_count, SUM(C.F_PRICE) AS cart_total_f_price, AVG(C.F_COUNT) AS cart_avg_f_count, COUNT(*) AS cart_total_buy FROM CART C JOIN TARGET_FURNITURE TF ON C.F_CODE = TF.F_CODE WHERE C.F_STATUS = 'Y' GROUP BY C.F_CODE) SELECT TF.*, NVL(RS.r_count, 0) AS r_count, NVL(RS.a_count, 0) AS a_count, NVL(RS.star_avg, 0) AS star_avg, NVL(CS.cart_total_f_count, 0) AS cart_total_f_count, NVL(CS.cart_total_f_price, 0) AS cart_total_f_price, NVL(CS.cart_avg_f_count, 0) AS cart_avg_f_count, NVL(CS.cart_total_buy, 0) AS cart_total_buy FROM TARGET_FURNITURE TF LEFT JOIN REVIEW_SUMMARY RS ON TF.F_CODE = RS.F_CODE LEFT JOIN CART_SUMMARY CS ON TF.F_CODE = CS.F_CODE ORDER BY TF.F_CREATEDDATE DESC

